import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function CourseReviews() {
  const user = useSelector((state) => state.auth.user);
  const [courses, setCourses] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [selectedCourseId, setSelectedCourseId] = useState("");
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  useEffect(() => {
    if (user?.role === "teacher") {
      fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setCourses(Array.isArray(data) ? data : []))
        .catch((error) => toast.error("Ошибка загрузки курсов"));
    } else if (user?.role === "student") {
      fetch(`http://localhost:3001/enrollments?userId=${user.id}`)
        .then((res) => res.json())
        .then((enrollments) => {
          const courseIds = enrollments.map((e) => e.courseId);
          if (courseIds.length > 0) {
            fetch(`http://localhost:3001/courses?id=${courseIds.join("&id=")}`)
              .then((res) => res.json())
              .then((data) => setCourses(Array.isArray(data) ? data : []))
              .catch((error) => toast.error("Ошибка загрузки курсов"));
          } else {
            setCourses([]);
          }
        })
        .catch((error) => toast.error("Ошибка загрузки записей"));
    }
    fetch(`http://localhost:3001/reviews${user.role === "student" ? `?userId=${user.id}` : ""}`)
      .then((res) => res.json())
      .then((data) => setReviews(Array.isArray(data) ? data : []))
      .catch((error) => toast.error("Ошибка загрузки отзывов"));
  }, [user]);

  async function handleSubmit(e) {
    e.preventDefault();
    if (!selectedCourseId || !rating || !comment) {
      toast.error("Заполните все поля!");
      return;
    }
    try {
      const existingReview = reviews.find(
        (r) => r.courseId === parseInt(selectedCourseId) && r.userId === user.id
      );
      if (existingReview) {
        toast.error("Вы уже оставили отзыв на этот курс!");
        return;
      }
      const newReview = {
        courseId: parseInt(selectedCourseId),
        userId: user.id,
        rating: parseInt(rating),
        comment,
        createdAt: new Date().toISOString(),
      };
      const response = await fetch("http://localhost:3001/reviews", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newReview),
      });
      if (response.ok) {
        const createdReview = await response.json();
        setReviews([...reviews, createdReview]);
        setRating("");
        setComment("");
        setSelectedCourseId("");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Вы оставили отзыв на курс "${courses.find((c) => c.id === parseInt(selectedCourseId))?.name}".`,
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Отзыв успешно добавлен!");
      } else {
        const errorData = await response.json();
        toast.error(`Не удалось добавить отзыв: ${errorData.message || "Ошибка сервера"}`);
      }
    } catch (error) {
      console.error("Review submit error:", error);
      toast.error("Сетевая ошибка при добавлении отзыва");
    }
  }

  if (user?.role !== "teacher" && user?.role !== "student") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Отзывы о курсах</h1>
      {user.role === "student" && (
        <div className="card shadow mb-4">
          <div className="card-body">
            <h2 className="card-title">Оставить отзыв</h2>
            <form onSubmit={handleSubmit}>
              <div className="mb-3">
                <label htmlFor="course" className="form-label">Курс</label>
                <select
                  id="course"
                  className="form-select"
                  value={selectedCourseId}
                  onChange={(e) => setSelectedCourseId(e.target.value)}
                  required
                >
                  <option value="">-- Выберите курс --</option>
                  {courses.map((course) => (
                    <option key={course.id} value={course.id}>
                      {course.name}
                    </option>
                  ))}
                </select>
              </div>
              <div className="mb-3">
                <label htmlFor="rating" className="form-label">Оценка (1–5)</label>
                <input
                  type="number"
                  id="rating"
                  className="form-control"
                  value={rating}
                  onChange={(e) => setRating(e.target.value)}
                  min="1"
                  max="5"
                  required
                />
              </div>
              <div className="mb-3">
                <label htmlFor="comment" className="form-label">Комментарий</label>
                <textarea
                  id="comment"
                  className="form-control"
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                  required
                />
              </div>
              <button type="submit" className="btn btn-primary w-100">Отправить отзыв</button>
            </form>
          </div>
        </div>
      )}
      <div className="card shadow">
        <div className="card-body">
          <h2 className="card-title">Отзывы</h2>
          {reviews.length === 0 ? (
            <p>Отзывов нет</p>
          ) : (
            <ul className="list-group">
              {reviews.map((review) => (
                <li key={review.id} className="list-group-item">
                  <strong>Курс: </strong>{courses.find((c) => c.id === review.courseId)?.name || "Неизвестный курс"}<br />
                  <strong>Оценка: </strong>{review.rating}/5<br />
                  <strong>Комментарий: </strong>{review.comment}<br />
                  <small>{new Date(review.createdAt).toLocaleString()}</small>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  );
}

export default CourseReviews;
